/* usimDlvryMgmtMapper.updateDlvryStateOpenOk */
UPDATE	MCP_REQUEST_SELF_DLVRY@DL_MCP
SET		DLVRY_STATE_CODE	= '04'
		, RVISN_DTTM		= SYSDATE
		, RVISN_ID			= #{sessionUserId, jdbcType=VARCHAR}
WHERE	SELF_DLVRY_IDX 		= #{selfDlvryIdx, jdbcType=VARCHAR}

/* usimDlvryMgmtMapper.updateUsimOpenOk */
UPDATE	NMCP_USIM_BUY_TXN@DL_MCP
SET		SVC_CNTR_NO		= #{contractNum, jdbcType=VARCHAR}
        , AMD_IP			= #{ipAddr, jdbcType=VARCHAR}
		, AMD_DT			= SYSDATE
		, AMD_ID			= #{sessionUserId, jdbcType=VARCHAR}
WHERE	USIM_BUY_SEQ 	= #{usimBuySeq, jdbcType=VARCHAR}

