		SELECT	/* usimDlvryMgmtMapper.getUsimBuySeqNotNull */
				USIM_BUY_SEQ
		FROM 	NMCP_USIM_BUY_TXN@DL_MCP
		WHERE 	MYSLF_DLVR_SEQ = #{selfDlvryIdx, jdbcType=VARCHAR}
        AND     REQ_USIM_SN = #{reqUsimSnOrg, jdbcType=VARCHAR}

