/* usimDlvryMgmtMapper.updateUsimBuyTxnSn */
UPDATE	NMCP_USIM_BUY_TXN@DL_MCP
SET		REQ_USIM_SN			= #{reqUsimSn, jdbcType=VARCHAR}

		, SVC_CNTR_NO		= #{contractNum, jdbcType=VARCHAR}

		, USIM_BUY_DIV_CD 	= (SELECT DECODE(DLVRY_TYPE,'01','SELF','02','NOW','03','03','SELF') FROM MCP_REQUEST_SELF_DLVRY@DL_MCP WHERE SELF_DLVRY_IDX = #{selfDlvryIdx, jdbcType=VARCHAR})
        , AMD_IP			= #{ipAddr, jdbcType=VARCHAR}
		, AMD_DT			= SYSDATE
		, AMD_ID			= #{sessionUserId, jdbcType=VARCHAR}
WHERE	USIM_BUY_SEQ 		= #{usimBuySeq, jdbcType=VARCHAR}

